{"path": "/tmp/sv-258dcd242f9d414d9c426e0c4791779b/CheckoutWizard.razor", "file_text": "<h3>Checkout</h3>

@if (_step == 1)
{
    <ShippingStep Shipping="_order.Shipping"
                  ShippingChanged="OnShippingChanged"
                  OnNext="GoToPayment" />
}
else
{
    <PaymentStep Payment="_order.Payment"
                 PaymentChanged="OnPaymentChanged"
                 OnBack="GoToShipping"
                 OnPlaceOrder="PlaceOrder" />
}

@code {
    /// <summary>Raised when the user completes the checkout by placing an order.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private int _step = 1;

    private void OnShippingChanged(ShippingInfo shipping)
    {
        _order.Shipping = shipping;
    }

    private void OnPaymentChanged(PaymentInfo payment)
    {
        _order.Payment = payment;
    }

    private void GoToPayment() => _step = 2;

    private void GoToShipping() => _step = 1;

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}
"}

{"path": "/tmp/sv-258dcd242f9d414d9c426e0c4791779b/ShippingStep.razor", "file_text": "<h4>Shipping Information</h4>

<label>
    Name
    <input value="@Shipping.Name"
           @oninput="e => Update(s => s.Name = e.Value?.ToString() ?? "")" />
</label>

<label>
    Address
    <input value="@Shipping.Address"
           @oninput="e => Update(s => s.Address = e.Value?.ToString() ?? "")" />
</label>

<label>
    City
    <input value="@Shipping.City"
           @oninput="e => Update(s => s.City = e.Value?.ToString() ?? "")" />
</label>

<label>
    Zip Code
    <input value="@Shipping.ZipCode"
           @oninput="e => Update(s => s.ZipCode = e.Value?.ToString() ?? "")" />
</label>

@if (!CanProceed)
{
    <p class="validation-message">Name and Address are required.</p>
}

<button disabled="@(!CanProceed)" @onclick="OnNext">Next</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback<ShippingInfo> ShippingChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    private bool CanProceed =>
        !string.IsNullOrWhiteSpace(Shipping.Name) &&
        !string.IsNullOrWhiteSpace(Shipping.Address);

    private async Task Update(Action<ShippingInfo> mutate)
    {
        mutate(Shipping);
        await ShippingChanged.InvokeAsync(Shipping);
    }
}
"}

